using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage: boundary & comparison tests ---

    [TestMethod]
    [DataRow(10, 10, 100.0, DisplayName = "Perfect score")]
    [DataRow(0, 10, 0.0, DisplayName = "Zero correct")]
    [DataRow(1, 1, 100.0, DisplayName = "Single question perfect")]
    [DataRow(7, 10, 70.0, DisplayName = "Typical score")]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_AnyValidInputs_ResultIsInZeroToHundred()
    {
        var result = _calculator.CalculatePercentage(7, 10);

        // Assert.IsInRange verifies: low <= actual <= high
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsGreaterThanZero()
    {
        var result = _calculator.CalculatePercentage(3, 10);

        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_NotPerfect_IsLessThanHundred()
    {
        var result = _calculator.CalculatePercentage(9, 10);

        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade: boundary tests at each grade threshold ---

    [TestMethod]
    [DataRow(100.0, "A", DisplayName = "100% -> A")]
    [DataRow(90.0, "A", DisplayName = "90% boundary -> A")]
    [DataRow(89.99, "B", DisplayName = "Just below 90% -> B")]
    [DataRow(80.0, "B", DisplayName = "80% boundary -> B")]
    [DataRow(79.99, "C", DisplayName = "Just below 80% -> C")]
    [DataRow(70.0, "C", DisplayName = "70% boundary -> C")]
    [DataRow(69.99, "D", DisplayName = "Just below 70% -> D")]
    [DataRow(60.0, "D", DisplayName = "60% boundary -> D")]
    [DataRow(59.99, "F", DisplayName = "Just below 60% -> F")]
    [DataRow(0.0, "F", DisplayName = "0% -> F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(
        double percentage, string expectedGrade)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expectedGrade, grade);
    }

    // --- NormalizeScore: range & comparison tests ---

    [TestMethod]
    public void NormalizeScore_TypicalScore_IsInRange()
    {
        var result = _calculator.NormalizeScore(75.0, 150.0);

        // Normalized result should always fall in [0, 100]
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calculator.NormalizeScore(50.0, 100.0);

        Assert.AreEqual(50.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAtHundred()
    {
        var result = _calculator.NormalizeScore(200.0, 100.0);

        // Even though raw > max, result is capped
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NonZeroRaw_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(1.0, 100.0);

        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        var result = _calculator.NormalizeScore(0.0, 100.0);

        Assert.AreEqual(0.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }
}

